import{_ as t,o,c as a,ae as r}from"./chunks/framework.BGHOrOyn.js";const f=JSON.parse('{"title":"OSINT","description":"https://securitytrails.com/blog/osint-tools","frontmatter":{"description":"https://securitytrails.com/blog/osint-tools"},"headers":[],"relativePath":"pen-testing/osint.md","filePath":"pen-testing/osint.md"}'),s={name:"pen-testing/osint.md"};function n(i,e,l,c,h,u){return o(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="osint" tabindex="-1">OSINT <a class="header-anchor" href="#osint" aria-label="Permalink to &quot;OSINT&quot;">​</a></h1><p>When you start an IT security investigation, the first phase you will face is the <strong>data reconnaissance and intel gathering about your target</strong>. Once you finish gathering information about your objective you will have all the needed information like IP addresses, domain names, servers, technology and much more so you can finally conduct your security tests.</p><p><strong>What are the best OSINT tools to get this valuable information? Are you looking to track people &amp; company data, domains, IPs, servers, and running software?</strong></p><p>We have the right answer to those questions. On this post, we will show you the top best Recon and Intel information gathering tools for IT Security Researchers.</p><ul><li><a href="https://securitytrails.com/blog/osint-tools#content-how-can-i-use-osint-tools-in-cybersecurity" target="_blank" rel="noreferrer">How can I use OSINT tools in cybersecurity?</a><ul><li><a href="https://securitytrails.com/blog/osint-tools#content-find-unknown-public-assets" target="_blank" rel="noreferrer">Find unknown-public assets</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-detect-outside-critical-company-data" target="_blank" rel="noreferrer">Detect outside critical company data</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-group-critical-data-into-useful-plans" target="_blank" rel="noreferrer">Group critical data into useful plans</a></li></ul></li><li><a href="https://securitytrails.com/blog/osint-tools#content-best-25-osint-tools-used-by-infosec-professionals" target="_blank" rel="noreferrer">Best 25 OSINT Tools used by InfoSec Professionals</a><ul><li><a href="https://securitytrails.com/blog/osint-tools#content-1-osint-framework" target="_blank" rel="noreferrer">1. OSINT Framework</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-2-checkusernames" target="_blank" rel="noreferrer">2. CheckUserNames</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-3-haveibeenpwned" target="_blank" rel="noreferrer">3. HaveIbeenPwned</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-4-securitytrails-api" target="_blank" rel="noreferrer">4. SecurityTrails API</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-5-censys" target="_blank" rel="noreferrer">5. Censys</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-6-wappalyzer" target="_blank" rel="noreferrer">6. Wappalyzer</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-7-google-dorks" target="_blank" rel="noreferrer">7. Google Dorks</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-8-maltego" target="_blank" rel="noreferrer">8. Maltego</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-9-recon-ng" target="_blank" rel="noreferrer">9. Recon-Ng</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-10-theharvester" target="_blank" rel="noreferrer">10. theHarvester</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-11-shodan" target="_blank" rel="noreferrer">11. Shodan</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-12-jigsaw" target="_blank" rel="noreferrer">12. Jigsaw</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-13-spiderfoot" target="_blank" rel="noreferrer">13. SpiderFoot</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-14-creepy" target="_blank" rel="noreferrer">14. Creepy</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-15-nmap" target="_blank" rel="noreferrer">15. Nmap</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-16-webshag" target="_blank" rel="noreferrer">16. WebShag</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-17-openvas" target="_blank" rel="noreferrer">17. OpenVAS</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-18-fierce" target="_blank" rel="noreferrer">18. Fierce</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-19-unicornscan" target="_blank" rel="noreferrer">19. Unicornscan</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-20-foca" target="_blank" rel="noreferrer">20. Foca</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-21-zoomeye" target="_blank" rel="noreferrer">21. ZoomEye</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-22-owasp-amass" target="_blank" rel="noreferrer">22. OWASP Amass</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-23-ivre" target="_blank" rel="noreferrer">23. IVRE</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-24-metagoofil" target="_blank" rel="noreferrer">24. Metagoofil</a></li><li><a href="https://securitytrails.com/blog/osint-tools#content-25-exiftool" target="_blank" rel="noreferrer">25. Exiftool</a></li></ul></li></ul><h2 id="¶how-can-i-use-osint-tools-in-cybersecurity" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-how-can-i-use-osint-tools-in-cybersecurity" target="_blank" rel="noreferrer">¶</a>How can I use OSINT tools in cybersecurity? <a class="header-anchor" href="#¶how-can-i-use-osint-tools-in-cybersecurity" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-how-can-i-use-osint-tools-in-cybersecurity)How can I use OSINT tools in cybersecurity?&quot;">​</a></h2><p>OSINT, as we explained in our previous article &#39;What is OSINT?&#39;, stands for Open Source Intelligence. And in the same way that military intelligence teams play a critical role in gaining advantage over the enemy, OSINT plays a critical role in the field of cybersecurity.</p><p>Open Source Intelligence fuels cybersecurity teams, letting blue, purple and red teams access a wide range of information such as network technologies, web-hosting servers, DNS records, software technologies, cloud assets, IoT devices, apps, databases, social media accounts, and much more.</p><p>OSINT is widely used within different types of organizations, companies, public and private agencies. Even the US government, back in 2005, <a href="https://www.govinfo.gov/content/pkg/CHRG-109hhrg24962/html/CHRG-109hhrg24962.htm" target="_blank" rel="noreferrer">stated</a> the importance of using Open Source Information effectively.</p><p>Imagine for a moment all that critical information falling into criminal hands. That could mark the beginning of an attack against your online assets.</p><p>Adopting the proper OSINT tools will help your company boost your cybersecurity defenses, or if you work on a red team, increase the amount of valuable information you&#39;ll get.</p><p>While Open Source Intelligence tools are frequently used toward a wide range of goals, they often focus on a few specific areas:</p><h3 id="¶find-unknown-public-assets" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-find-unknown-public-assets" target="_blank" rel="noreferrer">¶</a>Find unknown-public assets <a class="header-anchor" href="#¶find-unknown-public-assets" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-find-unknown-public-assets)Find unknown-public assets&quot;">​</a></h3><p>Public assets are all over the place, but the most dangerous assets are the ones you don&#39;t see, the unknown infrastructure assets. That&#39;s why creating a full map of your entire online infrastructure, as well as the other types of services you use, is the first thing that both the good guys and the bad guys will do during an information-gathering process.</p><p>This can lead to either a good-stronger defense, or falling victim to different kinds of cyber attacks launched against your organization.</p><h4 id="¶detect-outside-critical-company-data" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-detect-outside-critical-company-data" target="_blank" rel="noreferrer">¶</a>Detect outside critical company data <a class="header-anchor" href="#¶detect-outside-critical-company-data" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-detect-outside-critical-company-data)Detect outside critical company data&quot;">​</a></h4><p>Sometimes the data isn&#39;t on your company&#39;s public surface. Sometimes it&#39;s located elsewhere, and this often happens when you work with many 3rd- and 4th-party-related SaaS services. Among other common issues are mergers and acquisitions, that if overlooked, can invite external attack vectors into the parent company. And OSINT can prove highly useful during <a href="https://securitytrails.com/blog/cybersecurity-mergers-acquisitions" target="_blank" rel="noreferrer">cybersecurity auditing against mergers and acquisitions</a>.</p><h4 id="¶group-critical-data-into-useful-plans" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-group-critical-data-into-useful-plans" target="_blank" rel="noreferrer">¶</a>Group critical data into useful plans <a class="header-anchor" href="#¶group-critical-data-into-useful-plans" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-group-critical-data-into-useful-plans)Group critical data into useful plans&quot;">​</a></h4><p>Once you&#39;ve found the most useful data from all fronts by using the right OSINT tools, then it&#39;s time to collate and group all that data and transform it into functional plans. What are we gonna do with these open ports? Who&#39;s in charge of updating this outdated software? When are we going to remove these stale DNS records? All these questions, and more, can inform the creation of your most appropriate and actionable plans, after you&#39;ve grouped all your sensitive data as a foundation.</p><p>Now that you know what OSINT is, and how it&#39;s used for cybersecurity, let&#39;s jump right into the fun part: a brief review of all the recommended OSINT tools.</p><h3 id="¶best-25-osint-tools-used-by-infosec-professionals" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-best-25-osint-tools-used-by-infosec-professionals" target="_blank" rel="noreferrer">¶</a>Best 25 OSINT Tools used by InfoSec Professionals <a class="header-anchor" href="#¶best-25-osint-tools-used-by-infosec-professionals" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-best-25-osint-tools-used-by-infosec-professionals)Best 25 OSINT Tools used by InfoSec Professionals&quot;">​</a></h3><p><em><strong>Important note</strong></em> <em>before we start: remember that you should never use these tools on external networks/systems without previous authorization. These OSINT tools are presented here in order to help IT security researchers and private/public infosec investigators during the first phase of information gathering, which is one of the most important parts of a cybersecurity investigation.</em></p><figure><img src="https://assets.securitytrails.com/cdn-cgi/image/width=789,quality=100,format=auto/blog/osint-tools/top-osint-tools-banner4.jpg" alt=""><figcaption></figcaption></figure><h4 id="¶1-osint-framework" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-1-osint-framework" target="_blank" rel="noreferrer">¶</a>1. OSINT Framework <a class="header-anchor" href="#¶1-osint-framework" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-1-osint-framework)1. OSINT Framework&quot;">​</a></h4><p>While <a href="http://osintframework.com/" target="_blank" rel="noreferrer">OSINT Framework</a> isn&#39;t a tool to be run on your servers, it&#39;s a very useful way to get valuable information by querying free search engines, resources, and tools publicly available on the Internet. They are focused on bringing the best links to valuable sources of OSINT data.</p><p>While this web application was originally created focused on IT security, with the time it has evolved and today you can get other kinds of information from other industries as well. Most of the websites it uses to query the information are free, but some may require paying a low fee.</p><figure><img src="https://assets.securitytrails.com/cdn-cgi/image/width=789,quality=100,format=auto/blog/osint-tools/osint-framework.jpg" alt=""><figcaption></figcaption></figure><h4 id="¶2-checkusernames" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-2-checkusernames" target="_blank" rel="noreferrer">¶</a>2. CheckUserNames <a class="header-anchor" href="#¶2-checkusernames" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-2-checkusernames)2. CheckUserNames&quot;">​</a></h4><p><a href="https://checkusernames.com/" target="_blank" rel="noreferrer">CheckUserNames</a> is an online OSINT tool that can help you to find usernames across over 170 social networks. This is especially useful if you are running an investigation to determine the usage of the same username on different social networks.</p><p>It can be also used to check for brand company names, not only individuals.</p><h4 id="¶3-haveibeenpwned" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-3-haveibeenpwned" target="_blank" rel="noreferrer">¶</a>3. HaveIbeenPwned <a class="header-anchor" href="#¶3-haveibeenpwned" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-3-haveibeenpwned)3. HaveIbeenPwned&quot;">​</a></h4><p><a href="https://haveibeenpwned.com/" target="_blank" rel="noreferrer">HaveIbeenPwned</a> can help you to check if your account has been compromised in the past. This site was developed by Troy Hunt, one of the most respected IT security professionals of this market, and it&#39;s been serving accurate reports since years.</p><p>If you suspect your account has been compromised, or want to verify for 3rd party compromises on external accounts, this is the perfect tool. It can track down web compromise from many sources like Gmail, Hotmail, Yahoo accounts, as well as LastFM, Kickstarter, Wordpress.com, Linkedin and many other popular websites.</p><p>Once you introduce your email address, the results will be displayed, showing something like:</p><figure><img src="https://assets.securitytrails.com/cdn-cgi/image/width=789,quality=100,format=auto/blog/osint-tools/haveibeenpwned.jpg" alt=""><figcaption></figcaption></figure><h4 id="¶4-securitytrails-api" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-4-securitytrails-api" target="_blank" rel="noreferrer">¶</a>4. SecurityTrails API <a class="header-anchor" href="#¶4-securitytrails-api" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-4-securitytrails-api)4. SecurityTrails API&quot;">​</a></h4><p>The <a href="https://securitytrails.com/corp/api" target="_blank" rel="noreferrer">SecurityTrails API</a> allows you instant access to current DNS and historical records, domain details, and associated domains, IP information, as well as WHOIS data so you can integrate it within your own applications for asset discovery, threat intelligence, risk scoring, and much more. The best part is that you only need an HTTP request to retrieve the data, such as:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">--request GET \\</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">--url https://api.securitytrails.com/v1/history/netflix.com/dns/a \\</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">--header &#39;apikey: &gt;&#39;</span></span></code></pre></div><figure><img src="https://assets.securitytrails.com/cdn-cgi/image/width=789,quality=100,format=auto/blog/osint-tools/securitytrails-api.png" alt=""><figcaption></figcaption></figure><h4 id="¶5-censys" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-5-censys" target="_blank" rel="noreferrer">¶</a>5. Censys <a class="header-anchor" href="#¶5-censys" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-5-censys)5. Censys&quot;">​</a></h4><p><a href="https://censys.io/" target="_blank" rel="noreferrer">Censys</a> is a wonderful search engine used to get the latest and most accurate information about any device connected to the internet, it can be servers or domain names.</p><p>You will be able to find full geographic and technical details about 80 and 443 ports running on any server, as well as HTTP/S body content &amp; GET response of the target website, Chrome TLS Handshake, full SSL Certificate Chain information, and WHOIS information.</p><h4 id="¶6-wappalyzer" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-6-wappalyzer" target="_blank" rel="noreferrer">¶</a>6. Wappalyzer <a class="header-anchor" href="#¶6-wappalyzer" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-6-wappalyzer)6. Wappalyzer&quot;">​</a></h4><p><a href="https://www.wappalyzer.com/" target="_blank" rel="noreferrer">Wappalyzer</a> is a highly useful service that allows security researchers to quickly identify technologies on websites. With it, you can find a complete list of details for any technology stack running on any website. It also allows you to build lists of websites that use certain technologies, letting you add phone numbers and email addresses as well.</p><p>Their free plan includes instant results and up to 50 free monthly lookups. It’s perfect for tracking website technologies, discovering old/vulnerable software, finding organic data about your competitors, and last but not least, can be quickly triggered from the web browser with their Chrome/Firefox extensions.</p><p>If that isn’t enough, they also offer a handy API to automate technology lookups, and you can even set up website alerts to monitor your competition.</p><h4 id="¶7-google-dorks" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-7-google-dorks" target="_blank" rel="noreferrer">¶</a>7. Google Dorks <a class="header-anchor" href="#¶7-google-dorks" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-7-google-dorks)7. Google Dorks&quot;">​</a></h4><p>While investigating people or companies, a lot of IT security newbies forget the importance of using traditional search engines for recon and intel gathering.</p><p>In this case, <a href="https://securitytrails.com/blog/google-hacking-techniques" target="_blank" rel="noreferrer">Google Dorks</a> can be your best friend. They have been there since 2002 and can help you a lot in your intel reconnaissance.</p><p>Google Dorks are simply ways to query Google against certain information that may be useful for your security investigation.</p><p>Search engines index a lot of information about almost anything on the internet, including individual, companies, and their data.</p><p>Some popular operators used to perform Google Dorking:</p><ul><li>Filetype: you can use this dork to find any kind of filetypes.</li><li>Ext: can help you to find files with specific extensions (eg. .txt, .log, etc).</li><li>Intext: can perform queries helps to search for specific text inside any page.</li><li>Intitle: it will search for any specific words inside the page title.</li><li>Inurl: will look out for mentioned words inside the URL of any website.</li></ul><p>Log files aren&#39;t supposed to be indexed by search engines, however, they do, and you can get valuable information from these Google Dorks, as you see below:</p><figure><img src="https://assets.securitytrails.com/cdn-cgi/image/width=789,quality=100,format=auto/blog/osint-tools/google_dorks.png" alt=""><figcaption></figcaption></figure><p>Now let&#39;s focus on other more practical tools used by the most respected InfoSec professionals:</p><h4 id="¶8-maltego" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-8-maltego" target="_blank" rel="noreferrer">¶</a>8. Maltego <a class="header-anchor" href="#¶8-maltego" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-8-maltego)8. Maltego&quot;">​</a></h4><p>Is an amazing tool to track down footprints of any target you need to match. This piece of software has been developed by Paterva, and it&#39;s part of the Kali Linux distribution.</p><p>Using <a href="https://www.maltego.com/downloads/" target="_blank" rel="noreferrer">Maltego</a> will allow you to launch reconnaissance tests against specific targets.</p><p>One of the best things this software includes is what they call &#39;transforms&#39;. Transforms are available for free in some cases, and on others, you will find commercial versions only. They will help you to run a different kind of tests and data integration with external applications.</p><p>In order to use Maltego you need to open a free account on their website, after that, you can launch a new machine or run transforms on the target from an existing one. Once you have chosen your transforms, Maltego app will start running all the transforms from Maltego servers.</p><p>Finally, Maltego will show you the results for the specified target, like IP, domains, AS numbers, and much more.</p><hr><p>If you need to explore more Kali Linux utilities, check out this article: <a href="https://securitytrails.com/blog/kali-linux-tools" target="_blank" rel="noreferrer">Top 25 Kali Linux Tools</a></p><hr><h4 id="¶9-recon-ng" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-9-recon-ng" target="_blank" rel="noreferrer">¶</a>9. Recon-Ng <a class="header-anchor" href="#¶9-recon-ng" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-9-recon-ng)9. Recon-Ng&quot;">​</a></h4><p><a href="https://github.com/lanmaster53/recon-ng" target="_blank" rel="noreferrer">Recon-ng</a> comes already built in the Kali Linux distribution and is another great tool used to perform quickly and thoroughly reconnaissance on remote targets.</p><p>This web reconnaissance framework was written in Python and includes many modules, convenience functions and interactive help to guide you on how to use it properly.</p><p>The simple command-based interface allows you to run common operations like interacting with a database, run web requests, manage API keys or standardizing output content.</p><p>Fetching information about any target is pretty easy and can be done within seconds after installing. It includes interesting modules like google_site_web and bing_domain_web that can be used to find valuable information about the target domains.</p><p>While some recon-ng modules are pretty passive as they never hit the target network, others can launch interesting stuff right against the remote host.</p><figure><img src="https://assets.securitytrails.com/cdn-cgi/image/width=789,quality=100,format=auto/blog/osint-tools/recon-ng.png" alt=""><figcaption></figcaption></figure><h4 id="¶10-theharvester" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-10-theharvester" target="_blank" rel="noreferrer">¶</a>10. theHarvester <a class="header-anchor" href="#¶10-theharvester" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-10-theharvester)10. theHarvester&quot;">​</a></h4><p><a href="https://securitytrails.com/blog/theharvester-tool" target="_blank" rel="noreferrer">theHarvester</a> is another great alternative to fetch valuable information about any subdomain names, virtual hosts, open ports and email address of any company/website.</p><p>This is especially useful when you are in the first steps of a penetration test against your own local network, or against 3rd party authorized networks. Same as previous tools, theHarvester is included inside <a href="https://www.kali.org/" target="_blank" rel="noreferrer">Kali Linux</a> distro.</p><p>theHarvester uses many resources to fetch the data like PGP key servers, Bing, Baidu, Yahoo and Google search engine, and also social networks like Linkedin, Twitter and Google Plus.</p><p>It can also be used to launch active penetration test like DNS brute force based on dictionary attack, <a href="https://securitytrails.com/blog/reverse-dns" target="_blank" rel="noreferrer">rDNS lookups</a> and DNS TLD expansion using dictionary brute force enumeration.</p><h4 id="¶11-shodan" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-11-shodan" target="_blank" rel="noreferrer">¶</a>11. Shodan <a class="header-anchor" href="#¶11-shodan" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-11-shodan)11. Shodan&quot;">​</a></h4><p><a href="https://www.shodan.io/" target="_blank" rel="noreferrer">Shodan</a> is a network security monitor and search engine focused on the deep web &amp; the internet of things. It was created by John Matherly in 2009 to keep track of publicly accessible computers inside any network.</p><p>It is often called the &#39;search engine for hackers&#39;, as it lets you find and explore a different kind of devices connected to a network like servers, routers, webcams, and more.</p><p>Shodan is pretty much like Google, but instead of showing you fancy images and rich content / informative websites, it will show you things that are more related to the interest of IT security researchers like SSH, FTP, SNMP, Telnet, RTSP, IMAP and HTTP server banners and public information. Results will be shown ordered by country, operating system, network, and ports.</p><p>Shodan users are not only able to reach servers, webcams, and routers. It can be used to scan almost anything that is connected to the internet, including but not limited to traffic lights systems, home heating systems, water park control panels, water plants, nuclear power plants, and much more.</p><h4 id="¶12-jigsaw" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-12-jigsaw" target="_blank" rel="noreferrer">¶</a>12. Jigsaw <a class="header-anchor" href="#¶12-jigsaw" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-12-jigsaw)12. Jigsaw&quot;">​</a></h4><p><a href="https://www.jigsawsecurityenterprise.com/" target="_blank" rel="noreferrer">Jigsaw</a> is used to gather information about any company employees. This tool works perfectly for companies like Google, Linkedin, or Microsoft, where we can just pick up one of their domain names (like google.com), and then gather all their employee&#39;s emails on the different company departments.</p><p>The only drawback is that these queries are launched against Jigsaw database located at jigsaw.com, so, we depend entirely on what information they allow us to explore inside their database. You will be able to find information about big companies, but if you are exploring a not so famous startup then you may be out of luck.</p><h4 id="¶13-spiderfoot" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-13-spiderfoot" target="_blank" rel="noreferrer">¶</a>13. SpiderFoot <a class="header-anchor" href="#¶13-spiderfoot" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-13-spiderfoot)13. SpiderFoot&quot;">​</a></h4><p><a href="https://www.spiderfoot.net/" target="_blank" rel="noreferrer">SpiderFoot</a> is one of the best reconnaissance tools out there if you want to automate OSINT and have fast results for reconnaissance, threat intelligence, and perimeter monitoring.</p><p>It was written by our friend Steve Micallef, who did a great job building this app and writing the <a href="https://securitytrails.com/blog/add-on-for-splunk" target="_blank" rel="noreferrer">SecurityTrails Addon for Splunk</a></p><p>This recon tool can help you to launch queries over 100 public data sources to gather intelligence on generic names, domain names, email addresses, and IP addresses.</p><p>Using Spiderfoot is pretty much easy, just specify the target, choose which modules you want to run, and Spiderfoot will do the hard job for you collecting all the intel data from the modules.</p><h4 id="¶14-creepy" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-14-creepy" target="_blank" rel="noreferrer">¶</a>14. Creepy <a class="header-anchor" href="#¶14-creepy" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-14-creepy)14. Creepy&quot;">​</a></h4><p><a href="https://www.geocreepy.com/" target="_blank" rel="noreferrer">Creepy</a> is a geo-location OSINT tool for infosec professionals. It offers the ability to get full geolocation data from any individuals by querying social networking platforms like Twitter, Flickr, Facebook, etc.</p><p>If anyone uploads an image to any of these social networks with geolocation feature activated, then you will be able to see a full active mal where this person has been.</p><p>You will be able to filter based on exact locations, or even by date. After that, you can export the results in CSV or KML format.</p><figure><img src="https://assets.securitytrails.com/cdn-cgi/image/width=789,quality=100,format=auto/blog/osint-tools/creepy.jpg" alt=""><figcaption></figcaption></figure><h4 id="¶15-nmap" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-15-nmap" target="_blank" rel="noreferrer">¶</a>15. Nmap <a class="header-anchor" href="#¶15-nmap" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-15-nmap)15. Nmap&quot;">​</a></h4><p><a href="https://nmap.org/" target="_blank" rel="noreferrer">Nmap</a> is one of the most popular and widely used security auditing tools, its name means &quot;Network Mapper&quot;. Is a free and open source utility utilized for security auditing and network exploration across local and remote hosts.</p><p>Some of the main features include:</p><ul><li>Host detection: Nmap has the ability to identify hosts inside any network that have certain ports open, or that can send a response to ICMP and TCP packets.</li><li>IP and DNS information detection: including device type, Mac addresses and even reverse DNS names.</li><li>Port detection: Nmap can detect any port open on the target network, and let you know the possible running services on it.</li><li>OS detection: get full OS version detection and hardware specifications of any host connected.</li><li>Version detection: Nmap is also able to get application name and version number.</li></ul><h4 id="¶16-webshag" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-16-webshag" target="_blank" rel="noreferrer">¶</a>16. WebShag <a class="header-anchor" href="#¶16-webshag" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-16-webshag)16. WebShag&quot;">​</a></h4><p><a href="https://github.com/wereallfeds/webshag" target="_blank" rel="noreferrer">WebShag</a> is a great server auditing tool used to scan HTTP and HTTPS protocols. Same as other tools, it&#39;s part of Kali Linux and can help you a lot in your IT security research &amp; penetration testing.</p><p>You will be able to launch a simple scan, or use advanced methods like through a proxy, or over HTTP authentication.</p><p>Written in Python, it can be one of your best allies while auditing systems.</p><p>Main features include:</p><ul><li><a href="https://securitytrails.com/blog/best-port-scanners" target="_blank" rel="noreferrer">Port Scan</a></li><li>URL scanning</li><li>File fuzzing</li><li>Website crawling</li></ul><p>In order to avoid getting blocked by remote server security systems, it uses an intelligent IDS evasion system by launching random requests per HTTP proxy server, so you can keep auditing the server without being banned.</p><h4 id="¶17-openvas" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-17-openvas" target="_blank" rel="noreferrer">¶</a>17. OpenVAS <a class="header-anchor" href="#¶17-openvas" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-17-openvas)17. OpenVAS&quot;">​</a></h4><p><a href="http://www.openvas.org/" target="_blank" rel="noreferrer">OpenVAS</a> (Open Vulnerability Assessment System) is a security framework that includes particular services and tools for infosec professionals.</p><p>This is an open source vulnerability scanner &amp; security manager that was built after the famous Nessus switched from open source to private source. Then, the original developers of the Nessus vulnerability scanner decided to fork the original project and create OpenVAS.</p><p>While it is a little bit more difficult to setup than the old Nessus, it&#39;s quite effective while working with it to analyze the security of remote hosts.</p><p>The main tool included in OpenVAS is OpenVAS Scanner, a highly efficient agent that executes all the network vulnerability tests over the target machine.</p><p>On the other hand, another main component is called OpenVAS Manager, which is basically vulnerability management solution that allows you to store scanned data into an SQLite database, so then you can search, filter and order the scan results in a fancy and easy way.</p><h4 id="¶18-fierce" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-18-fierce" target="_blank" rel="noreferrer">¶</a>18. Fierce <a class="header-anchor" href="#¶18-fierce" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-18-fierce)18. Fierce&quot;">​</a></h4><p><a href="https://github.com/mschwager/fierce" target="_blank" rel="noreferrer">Fierce</a> is an IP and DNS recon tool written in PERL, famous for helping IT sec professionals to find target IPs associated with domain names.</p><p>It was written originally by RSnake along with other members of the old <a href="http://ha.ckers.org/" target="_blank" rel="noreferrer">http://ha.ckers.org/</a>. It&#39;s used mostly targetting local and remote corporate networks.</p><p>Once you have defined your target network, it will launch several scans against the selected domains and then it will try to find misconfigured networks and vulnerable points that can later leak private and valuable data.</p><p>The results will be ready within a few minutes, a little bit more than when you perform any other scan with similar tools like Nessus, <a href="https://securitytrails.com/blog/nikto-website-vulnerability-scanner" target="_blank" rel="noreferrer">Nikto</a>, Unicornscan, etc.</p><figure><img src="https://assets.securitytrails.com/cdn-cgi/image/width=789,quality=100,format=auto/blog/osint-tools/fierce.png" alt=""><figcaption></figcaption></figure><h4 id="¶19-unicornscan" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-19-unicornscan" target="_blank" rel="noreferrer">¶</a>19. Unicornscan <a class="header-anchor" href="#¶19-unicornscan" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-19-unicornscan)19. Unicornscan&quot;">​</a></h4><p><a href="https://github.com/dneufeld/unicornscan" target="_blank" rel="noreferrer">Unicornscan</a> is one of the top intel gathering tools for security research. It has also a built-in correlation engine that aims to be efficient, flexible and scalable at the same time.</p><p>Main features include:</p><ul><li>Full TCP/IP device/network scan.</li><li>Asynchronous stateless TCP scanning (including all TCP Flags variations).</li><li>Asynchronous TCP banner detection.</li><li>UDP Protocol scanning.</li><li>A/P OS identification.</li><li>Application and component detection.</li><li>Support for SQL Relational Output</li></ul><h4 id="¶20-foca" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-20-foca" target="_blank" rel="noreferrer">¶</a>20. Foca <a class="header-anchor" href="#¶20-foca" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-20-foca)20. Foca&quot;">​</a></h4><p><a href="https://www.elevenpaths.com/innovation-labs/technologies/foca" target="_blank" rel="noreferrer">FOCA</a> (Fingerprinting Organizations with Collected Archives) is a tool written by ElevenPaths that can be used to scan, analyze, extract and classify information from remote web servers and their hidden information.</p><p>Foca has the ability to analyze and collect valuable data from MS Office suite, OpenOffice, PDF, as well as Adobe InDesign and SVG and GIF files. This security tool also works actively with Google, Bing and DuckDuckGo search engines to collect additional data from those files. Once you have the full file list, it starts extracting information to attempt to identify more valuable data from the files.</p><h4 id="¶21-zoomeye" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-21-zoomeye" target="_blank" rel="noreferrer">¶</a>21. ZoomEye <a class="header-anchor" href="#¶21-zoomeye" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-21-zoomeye)21. ZoomEye&quot;">​</a></h4><p>In the cybersecurity world, we researchers are used to popular IoT search engines such as Shodan or Censys. For a while, however, a powerful new IoT search engine has been rapidly gaining followers. We&#39;re talking about ZoomEye.</p><p><a href="https://www.zoomeye.org/" target="_blank" rel="noreferrer">ZoomEye</a> is a Chinese IoT OSINT search engine that allows users to grab public data from exposed devices and web services. In order to build its database it uses Wmap and Xmap, and then runs extensive fingerprinting against all the information found, ultimately presenting it to users in a filtered and curated way for easy visualization.</p><p>What information can you find with ZoomEye?</p><ul><li>IPs interacting with networks and hosts</li><li>Open ports on remote servers</li><li>Total number of hosted websites</li><li>Total number of devices found</li><li>Interactive map of users hitting different devices</li><li>Vulnerabilities report</li></ul><p>And much more. The public version offers access to a lot of data—but if you want to see what it can really do, we suggest you sign up for a free account. That way you&#39;ll get to test the real power of this OSINT tool.</p><h4 id="¶22-owasp-amass" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-22-owasp-amass" target="_blank" rel="noreferrer">¶</a>22. OWASP Amass <a class="header-anchor" href="#¶22-owasp-amass" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-22-owasp-amass)22. OWASP Amass&quot;">​</a></h4><p>Originally written by our friend Jeff Foley, <a href="https://securitytrails.com/blog/owasp-amass" target="_blank" rel="noreferrer">OWASP Amass</a> is probably one of the best reconnaissance and network mapping tools in the market. It&#39;s widely used for network discovery, DNS enumeration, and general attack surface mapping tasks with a varied set of techniques, with a heavy focus on intel gathering and data scrapping on HTTP, SSL/TLS, and DNS protocols.</p><p>And if that’s not enough, it also provides API integrations with popular cybersecurity data services, such as our own SecurityTrails API.</p><h4 id="¶23-ivre" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-23-ivre" target="_blank" rel="noreferrer">¶</a>23. IVRE <a class="header-anchor" href="#¶23-ivre" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-23-ivre)23. IVRE&quot;">​</a></h4><p>This infosec tool is frequently overlooked, but it has great potential in boosting your infosec discovery and analysis processes. <a href="https://doc.ivre.rocks/en/latest/" target="_blank" rel="noreferrer">IVRE</a> is an open source tool that&#39;s built on a base of popular projects like Nmap, Masscan, ZDNS, and ZGrab2.</p><p>Its framework uses these popular tools to gather network intelligence on any host, then uses a MongoDB database to store the data.</p><p>Its web-based interface makes it easy for both beginning and advanced infosec users to perform the following actions:</p><ul><li>Passive reconnaissance by flow analysis (from Zeek, Argus or nfdump)</li><li>Active reconnaissance by using Zmap and Nmap</li><li>Fingerprinting analysis</li><li>Import data from other 3rd party infosec apps, such as Masscan/Nmap</li></ul><p>IVRE can be installed by fetching the source from their official Github repo, or from 3rd-party repositories such as Kali Linux repo.</p><h4 id="¶24-metagoofil" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-24-metagoofil" target="_blank" rel="noreferrer">¶</a>24. Metagoofil <a class="header-anchor" href="#¶24-metagoofil" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-24-metagoofil)24. Metagoofil&quot;">​</a></h4><p><a href="https://tools.kali.org/information-gathering/metagoofil" target="_blank" rel="noreferrer">Metagoofil</a> is another great intel-reconnaissance tool that aims to help infosec researchers, IT managers, and red teams to extract metadata from different types of files, such as:</p><ul><li>doc</li><li>docx</li><li>pdf</li><li>xls</li><li>xlsx</li><li>ppt</li><li>pptx</li></ul><p>How does it work? This app performs a deep search on search engines like Google, focusing on these types of files. Once it detects such a file, it will download it to your local storage, then proceed to extract all of its valuable data.</p><p>Once the extraction is complete, you&#39;ll see a full report with usernames, software banners, app versions, hostnames and more, a valuable resource for your recon phase.</p><p>Metagoofil also includes a number of options to help you filter the types of files to search for, refine the results and tweak the output, among many other useful features.</p><h4 id="¶25-exiftool" tabindex="-1"><a href="https://securitytrails.com/blog/osint-tools#content-25-exiftool" target="_blank" rel="noreferrer">¶</a>25. Exiftool <a class="header-anchor" href="#¶25-exiftool" aria-label="Permalink to &quot;[¶](https://securitytrails.com/blog/osint-tools#content-25-exiftool)25. Exiftool&quot;">​</a></h4><p>While a lot of OSINT tools focus on data found on public files such as PDF, .DOC, HTML, .SQL, etc., there are other tools that are specifically designed to extract critical Open Source Intelligence data from image, video and audio files.</p><p><a href="https://exiftool.org/" target="_blank" rel="noreferrer">Exiftool</a> reads, writes and extracts metadata from the following types of files:</p><ul><li>EXIF</li><li>IPTC</li><li>GPS</li><li>XMP</li><li>JFIF</li><li><a href="https://exiftool.org/%23supported" target="_blank" rel="noreferrer">And many others</a></li></ul><p>It also supports native files from a wide range of cameras, such as: Canon, Casio, FujiFilm, Kodak, Sony, and many others. It&#39;s also conveniently available on multiple platforms including Linux, Windows and MacOS.</p>`,151)])])}const d=t(s,[["render",n]]);export{f as __pageData,d as default};
